def _parse_blob_url(blob_url: str):
    # Expected: https://{account}.blob.core.windows.net/{container}/{blobpath}
    # Also supports SAS; query string ignored.
    from urllib.parse import urlparse

    u = urlparse(blob_url)
    if not u.scheme.startswith("http"):
        raise ValueError(f"Invalid blob URL: {blob_url}")

    host = u.netloc
    path = u.path.lstrip("/")
